"""
Monitors npm/PyPI registry streams for suspicious new packages.
Streams real-time publish events and scores each for anomalies.

Install: pip install aiohttp
Usage:   python registry-stream-monitor.py
"""

import asyncio, aiohttp, json, hashlib, re
from datetime import datetime, timezone
from dataclasses import dataclass, field
from typing import Optional
import logging

logging.basicConfig(level=logging.INFO, format="%(asctime)s %(levelname)s %(message)s")
log = logging.getLogger(__name__)

SUSPICIOUS_PATTERNS = [
    r"^(npm|node|react|vue|angular|webpack|babel|eslint|jest|mocha)\d+$",
    r"^(requests|flask|django|numpy|pandas|scipy|sklearn)\d+$",
]
COMPILED = [re.compile(p, re.I) for p in SUSPICIOUS_PATTERNS]

@dataclass
class PackageEvent:
    registry: str
    name: str
    version: str
    author: str
    published_at: datetime
    description: str = ""
    risk_score: float = 0.0
    flags: list = field(default_factory=list)

def score_package(pkg: PackageEvent) -> PackageEvent:
    score = 0.0; flags = []
    for pat in COMPILED:
        if pat.match(pkg.name): score += 0.6; flags.append("typosquat_pattern"); break
    if len(pkg.author) <= 2: score += 0.2; flags.append("anonymous_author")
    if not pkg.description or len(pkg.description) < 10: score += 0.15; flags.append("no_description")
    if any(kw in pkg.description.lower() for kw in ["postinstall","eval(","exec("]):
        score += 0.8; flags.append("install_hook_keyword")
    pkg.risk_score = min(score, 1.0); pkg.flags = flags
    return pkg

async def stream_pypi_rss(session: aiohttp.ClientSession, queue: asyncio.Queue):
    import xml.etree.ElementTree as ET
    url = "https://pypi.org/rss/updates.xml"
    seen = set()
    while True:
        try:
            async with session.get(url, timeout=aiohttp.ClientTimeout(total=15)) as resp:
                text = await resp.text()
                root = ET.fromstring(text)
                for item in root.iter("item"):
                    title = item.findtext("title",""); link = item.findtext("link","")
                    key = hashlib.md5(link.encode()).hexdigest()
                    if key in seen: continue
                    seen.add(key)
                    parts = title.rsplit(" ",1)
                    name = parts[0] if parts else title; version = parts[1] if len(parts)>1 else "unknown"
                    await queue.put(PackageEvent(registry="pypi",name=name,version=version,
                        author="unknown",published_at=datetime.now(timezone.utc),
                        description=item.findtext("description","")))
        except Exception as e: log.warning("PyPI RSS error: %s", e)
        await asyncio.sleep(60)

async def process_events(queue: asyncio.Queue, alert_threshold: float = 0.5):
    while True:
        pkg = await queue.get()
        pkg = score_package(pkg)
        if pkg.risk_score >= alert_threshold:
            log.warning("ALERT [%s] %s@%s risk=%.2f flags=%s",
                pkg.registry.upper(), pkg.name, pkg.version, pkg.risk_score, pkg.flags)
        queue.task_done()

async def main():
    queue: asyncio.Queue = asyncio.Queue(maxsize=1000)
    async with aiohttp.ClientSession() as session:
        await asyncio.gather(stream_pypi_rss(session, queue), process_events(queue))

if __name__ == "__main__":
    asyncio.run(main())
